// -------------------- HELPER FUNCTIONS --------------------

function hashSlug(slug: string): number {
  let h = 0;
  for (let i = 0; i < slug.length; i++) {
    h = (h * 31 + slug.charCodeAt(i)) >>> 0;
  }
  return h;
}

function applyVars(text: string, vars: Vars): string {
  return text
    .replaceAll("{name}", vars.name)
    .replaceAll("{stadt}", vars.stadt)
    .replaceAll("{service}", vars.service);
}

/**
 * Liefert alle 6 FAQ-Gruppen, je mit einer dozentinnen-spezifischen
 * Variante (deterministisch per Slug). _count wird ignoriert (Kompatibilität mit v1).
 */
export function getDozentinFaqs(slug: string, vars: Vars, _count?: number): FaqItem[] {
  return faqGroups.map((group) => {
    const h = hashSlug(slug + String(group.id));
    const idx = h % group.fragen.length;
    return {
      frage:   applyVars(group.fragen[idx],   vars),
      antwort: applyVars(group.antworten[idx], vars),
    };
  });
}

/** Liefert genau einen festen Bio-Text für die Dozentin. */
export function getDozentinBio(slug: string, vars: Vars): string {
  const h = hashSlug(slug + "bio");
  const bio = bioPool[h % bioPool.length];
  return applyVars(bio, vars);
}
